CREATE OR REPLACE FUNCTION public.corregir_operacion_v6(p_input jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Variables de entrada
    v_operacion_id_raw text;
    v_operacion_id_final text;
    v_producto_busqueda text;
    v_nuevo_nombre text;
    v_nuevo_precio numeric;
    v_nueva_cantidad int;

    -- Variables internas
    v_tipo text;
    v_item_id bigint;
    v_count int;
    v_nombres_encontrados text;
    v_total_nuevo numeric;
BEGIN
    -- 1. EXTRACCIÓN (ADAPTADA A TU JSON DE N8N)
    -- Aquí corregimos el error de nombres:
    v_operacion_id_raw := NULLIF(TRIM(p_input->>'id_final'), '');      -- Antes buscaba 'operacion_id'
    v_producto_busqueda := NULLIF(TRIM(p_input->>'producto'), '');     -- Antes buscaba 'detalle_a_corregir'
    v_nuevo_nombre := NULLIF(TRIM(p_input->>'nuevo_nombre'), '');

    -- Casting seguro (leemos directo del nivel raíz del JSON)
    BEGIN
        v_nuevo_precio := (p_input->>'nuevo_precio')::numeric;
        v_nueva_cantidad := (p_input->>'nueva_cantidad')::int;
    EXCEPTION WHEN OTHERS THEN
        v_nuevo_precio := NULL; v_nueva_cantidad := NULL;
    END;

    -- 🚨 VALIDACIÓN TEMPRANA
    IF v_operacion_id_raw IS NULL THEN
        RETURN jsonb_build_object(
            'success', false, 
            'error', 'El id_final llegó vacío (NULL).',
            'debug_input', p_input
        );
    END IF;

    -- 2. RESOLVER "ULTIMA"
    IF v_operacion_id_raw = 'ULTIMA' THEN
        SELECT operacion_id INTO v_operacion_id_final
        FROM public.historial_bot WHERE estado = 'EXITO' ORDER BY log_id DESC LIMIT 1;

        IF v_operacion_id_final IS NULL THEN 
            RETURN jsonb_build_object('success', false, 'error', 'No encontré historial para "ULTIMA".'); 
        END IF;
    ELSE
        v_operacion_id_final := v_operacion_id_raw;
    END IF;

    -- 3. DETECTAR TIPO
    v_tipo := split_part(v_operacion_id_final, '_', 1);

    -- 4. LÓGICA VENTA
    IF v_tipo = 'VENTA' THEN
        IF v_producto_busqueda IS NULL THEN
            RETURN jsonb_build_object('success', false, 'error', 'El campo "producto" vino vacío.');
        END IF;

        -- Buscar coincidencias
        SELECT COUNT(*), STRING_AGG(producto, ', ') INTO v_count, v_nombres_encontrados
        FROM public.ventas_detalles 
        WHERE venta_id = v_operacion_id_final AND producto ILIKE '%' || v_producto_busqueda || '%';

        IF v_count > 1 THEN
            RETURN jsonb_build_object('success', false, 'error', '⚠️ Ambigüedad: hay ' || v_count || ' productos: (' || COALESCE(v_nombres_encontrados, '') || '). Sé más específico.');
        END IF;

        IF v_count = 0 THEN
            RETURN jsonb_build_object('success', false, 'error', 'No encontré "' || v_producto_busqueda || '" en la venta ' || v_operacion_id_final);
        END IF;

        -- Obtener ID
        SELECT id INTO v_item_id FROM public.ventas_detalles 
        WHERE venta_id = v_operacion_id_final AND producto ILIKE '%' || v_producto_busqueda || '%' LIMIT 1;

        -- UPDATE
        UPDATE public.ventas_detalles
        SET 
            producto = COALESCE(v_nuevo_nombre, producto),
            precio_unitario = COALESCE(v_nuevo_precio, precio_unitario),
            cantidad = COALESCE(v_nueva_cantidad, cantidad),
            subtotal = (COALESCE(v_nueva_cantidad, cantidad) * COALESCE(v_nuevo_precio, precio_unitario))
        WHERE id = v_item_id;

        -- RECALCULAR
        SELECT COALESCE(SUM(subtotal),0) INTO v_total_nuevo FROM public.ventas_detalles WHERE venta_id = v_operacion_id_final;
        UPDATE public.ventas SET total = v_total_nuevo WHERE venta_id = v_operacion_id_final;
        UPDATE public.movimientos_dinero SET monto = v_total_nuevo WHERE referencia_id = v_operacion_id_final;

    -- (Si necesitas COMPRAS o RESERVAS, avísame y te paso el bloque completo, por ahora priorizo que funcione la VENTA)

    ELSE
        RETURN jsonb_build_object('success', false, 'error', 'Tipo desconocido o ID inválido: ' || COALESCE(v_operacion_id_final, 'NULL'));
    END IF;

    RETURN jsonb_build_object(
        'success', true, 
        'mensaje', '✅ Corrección aplicada a ' || v_operacion_id_final || '. Nuevo Total: $' || v_total_nuevo,
        'datos_usados', jsonb_build_object('id', v_operacion_id_final, 'producto', v_producto_busqueda, 'precio_nuevo', v_nuevo_precio)
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', 'Error SQL Crítico: ' || SQLERRM);
END;
$function$

CREATE OR REPLACE FUNCTION public.corregir_operacion_v11(p_input jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Variables de Cabecera
    v_operacion_id_raw text;
    v_operacion_id_final text;
    v_tipo text;

    -- Variables de Iteración
    rec_item record;
    v_items_json jsonb; -- <--- NUEVA VARIABLE PARA NORMALIZAR ENTRADA
    v_producto_busqueda text;
    v_nuevo_nombre text;
    v_nuevo_precio numeric;
    v_nueva_cantidad numeric;

    -- Variables de Auditoría (Valores viejos)
    v_old_cantidad numeric;
    v_old_precio numeric;
    v_old_nombre text;
    v_item_id bigint;

    -- Variables de Reporte
    v_total_recalculado numeric := 0;
    v_cambios_realizados int := 0;
    v_reporte_detallado text := ''; 
    v_log_errores text := '';
BEGIN
    -- 1. IDENTIFICAR OPERACIÓN
    v_operacion_id_raw := NULLIF(TRIM(p_input->>'id_final'), '');

    IF v_operacion_id_raw IS NULL THEN 
        RETURN jsonb_build_object('success', false, 'error', 'ID de operación no especificado.'); 
    END IF;

    -- 2. RESOLVER "ULTIMA"
    IF v_operacion_id_raw = 'ULTIMA' THEN
        SELECT operacion_id INTO v_operacion_id_final
        FROM public.historial_bot 
        WHERE estado = 'EXITO' AND operacion_id IS NOT NULL
        ORDER BY log_id DESC LIMIT 1;

        IF v_operacion_id_final IS NULL THEN 
            RETURN jsonb_build_object('success', false, 'error', 'Historial vacío.'); 
        END IF;
    ELSE
        v_operacion_id_final := v_operacion_id_raw;
    END IF;

    v_tipo := split_part(v_operacion_id_final, '_', 1);

    -- 3. ITERAR SOBRE LOS ÍTEMS A CORREGIR
    -- =========================================================
    -- LÓGICA HÍBRIDA: Soporta {items: []} y objeto plano {}
    -- =========================================================
    IF p_input ? 'items' THEN
        v_items_json := p_input->'items';
    ELSE
        -- Si no hay array "items", asumimos que el input es el ítem único
        v_items_json := jsonb_build_array(p_input);
    END IF;

    FOR rec_item IN SELECT * FROM jsonb_array_elements(v_items_json)
    LOOP
        v_producto_busqueda := NULLIF(TRIM(rec_item.value->>'producto'), '');
        v_nuevo_nombre      := NULLIF(TRIM(rec_item.value->>'nuevo_nombre'), '');

        BEGIN
            v_nuevo_precio := (rec_item.value->>'nuevo_precio')::numeric;
            v_nueva_cantidad := (rec_item.value->>'nueva_cantidad')::numeric;
        EXCEPTION WHEN OTHERS THEN
            v_nuevo_precio := NULL; v_nueva_cantidad := NULL;
        END;

        IF v_producto_busqueda IS NOT NULL THEN

            -- LÓGICA VENTA
            IF v_tipo = 'VENTA' THEN
                -- A. Buscar Datos Viejos
                SELECT id, cantidad, precio_unitario, producto 
                INTO v_item_id, v_old_cantidad, v_old_precio, v_old_nombre
                FROM public.ventas_detalles 
                WHERE venta_id = v_operacion_id_final 
                  AND (producto ILIKE v_producto_busqueda OR producto ILIKE '%' || v_producto_busqueda || '%')
                ORDER BY length(producto) ASC LIMIT 1;

                IF v_item_id IS NOT NULL THEN
                    -- B. Construir Reporte de Cambios
                    v_reporte_detallado := v_reporte_detallado || E'\n📝 *' || v_old_nombre || '*:';

                    IF v_nuevo_nombre IS NOT NULL AND v_nuevo_nombre != v_old_nombre THEN
                        v_reporte_detallado := v_reporte_detallado || ' Nombre cambiado a "' || v_nuevo_nombre || '".';
                    END IF;

                    IF v_nueva_cantidad IS NOT NULL AND v_nueva_cantidad != v_old_cantidad THEN
                        v_reporte_detallado := v_reporte_detallado || ' Cant: ' || v_old_cantidad || ' -> ' || v_nueva_cantidad || '.';
                    END IF;

                    IF v_nuevo_precio IS NOT NULL AND v_nuevo_precio != v_old_precio THEN
                        v_reporte_detallado := v_reporte_detallado || ' Precio: $' || v_old_precio || ' -> $' || v_nuevo_precio || '.';
                    END IF;

                    -- C. Actualizar
                    UPDATE public.ventas_detalles
                    SET 
                        producto = COALESCE(v_nuevo_nombre, producto),
                        precio_unitario = COALESCE(v_nuevo_precio, precio_unitario),
                        cantidad = COALESCE(v_nueva_cantidad::int, cantidad),
                        subtotal = (COALESCE(v_nueva_cantidad::int, cantidad) * COALESCE(v_nuevo_precio, precio_unitario))
                    WHERE id = v_item_id;
                    v_cambios_realizados := v_cambios_realizados + 1;
                ELSE
                    v_log_errores := v_log_errores || ' ❌ No encontré "' || v_producto_busqueda || '".';
                END IF;

            -- LÓGICA COMPRA
            ELSIF v_tipo = 'COMPRA' THEN
                SELECT id, cantidad, precio_unitario::numeric, producto 
                INTO v_item_id, v_old_cantidad, v_old_precio, v_old_nombre
                FROM public.compras_detalles 
                WHERE compra_id = v_operacion_id_final 
                  AND (producto ILIKE v_producto_busqueda OR producto ILIKE '%' || v_producto_busqueda || '%')
                ORDER BY length(producto) ASC LIMIT 1;

                IF v_item_id IS NOT NULL THEN
                    -- Construir Reporte Compra
                    v_reporte_detallado := v_reporte_detallado || E'\n📝 *' || v_old_nombre || '*:';

                    IF v_nuevo_nombre IS NOT NULL AND v_nuevo_nombre != v_old_nombre THEN
                        v_reporte_detallado := v_reporte_detallado || ' Nombre cambiado a "' || v_nuevo_nombre || '".';
                    END IF;

                    IF v_nueva_cantidad IS NOT NULL AND v_nueva_cantidad != v_old_cantidad THEN
                        v_reporte_detallado := v_reporte_detallado || ' Cant: ' || v_old_cantidad || ' -> ' || v_nueva_cantidad || '.';
                    END IF;

                    IF v_nuevo_precio IS NOT NULL AND v_nuevo_precio != v_old_precio THEN
                        v_reporte_detallado := v_reporte_detallado || ' Costo: $' || v_old_precio || ' -> $' || v_nuevo_precio || '.';
                    END IF;

                    UPDATE public.compras_detalles
                    SET 
                        producto = COALESCE(v_nuevo_nombre, producto),
                        precio_unitario = COALESCE(v_nuevo_precio::text, precio_unitario),
                        cantidad = COALESCE(v_nueva_cantidad, cantidad),
                        subtotal = (COALESCE(v_nueva_cantidad, cantidad) * COALESCE(v_nuevo_precio, precio_unitario::numeric))::text
                    WHERE id = v_item_id;
                    v_cambios_realizados := v_cambios_realizados + 1;
                ELSE
                    v_log_errores := v_log_errores || ' ❌ No encontré "' || v_producto_busqueda || '".';
                END IF;
            END IF;
        END IF;
    END LOOP;

    -- 4. RECALCULO FINAL
    IF v_cambios_realizados > 0 THEN
        IF v_tipo = 'VENTA' THEN
            SELECT COALESCE(SUM(subtotal), 0) INTO v_total_recalculado 
            FROM public.ventas_detalles WHERE venta_id = v_operacion_id_final;

            UPDATE public.ventas SET total_venta = v_total_recalculado::text WHERE venta_id = v_operacion_id_final;
            UPDATE public.movimientos_dinero SET monto = v_total_recalculado::text WHERE referencia_id = v_operacion_id_final AND tipo = 'ENTRADA';

        ELSIF v_tipo = 'COMPRA' THEN
            SELECT COALESCE(SUM(subtotal::numeric), 0) INTO v_total_recalculado 
            FROM public.compras_detalles WHERE compra_id = v_operacion_id_final;

            UPDATE public.compras SET total_compra = v_total_recalculado::text WHERE compra_id = v_operacion_id_final;
            UPDATE public.movimientos_dinero SET monto = v_total_recalculado::text WHERE referencia_id = v_operacion_id_final AND tipo = 'SALIDA';
        END IF;

        -- RETORNO FINAL CON EL REPORTE DETALLADO
        RETURN jsonb_build_object(
            'success', true, 
            'mensaje', '✅ Corrección aplicada.' || v_reporte_detallado || E'\n\n💰 *Nuevo Total: $' || v_total_recalculado || '*' || v_log_errores
        );
    ELSE
        RETURN jsonb_build_object(
            'success', false, 
            'error', 'No se realizaron cambios. ' || v_log_errores
        );
    END IF;

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', 'Error SQL v11: ' || SQLERRM);
END;
$function$

CREATE OR REPLACE FUNCTION public.corregir_operacion_v10(p_input jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Variables de Cabecera
    v_operacion_id_raw text;
    v_operacion_id_final text;
    v_tipo text;
    
    -- Variables de Iteración
    rec_item record;
    v_producto_busqueda text;
    v_nuevo_nombre text;
    v_nuevo_precio numeric;
    v_nueva_cantidad numeric;
    
    -- Variables Internas
    v_item_id bigint;
    v_count int;
    v_total_recalculado numeric := 0;
    v_cambios_realizados int := 0;
    v_log_errores text := '';
BEGIN
    -- 1. IDENTIFICAR OPERACIÓN
    v_operacion_id_raw := NULLIF(TRIM(p_input->>'id_final'), '');

    IF v_operacion_id_raw IS NULL THEN 
        RETURN jsonb_build_object('success', false, 'error', 'ID de operación no especificado.'); 
    END IF;

    -- 2. RESOLVER "ULTIMA" O ID DIRECTO
    IF v_operacion_id_raw = 'ULTIMA' THEN
        -- Buscamos en el historial del bot la última operación exitosa
        -- Ojo: Ajustar si tu lógica de historial es diferente
        SELECT operacion_id INTO v_operacion_id_final
        FROM public.historial_bot 
        WHERE estado = 'EXITO' 
          AND operacion_id IS NOT NULL
        ORDER BY log_id DESC 
        LIMIT 1;
        
        IF v_operacion_id_final IS NULL THEN 
            RETURN jsonb_build_object('success', false, 'error', 'No se encontró ninguna operación anterior en el historial.'); 
        END IF;
    ELSE
        v_operacion_id_final := v_operacion_id_raw;
    END IF;

    -- 3. DETECTAR TIPO DE OPERACIÓN (VENTA_..., COMPRA_...)
    v_tipo := split_part(v_operacion_id_final, '_', 1);

    -- 4. ITERAR SOBRE LOS ÍTEMS A CORREGIR
    -- El JSON trae: { items: [ { producto: "...", nuevo_precio: ... }, ... ] }
    FOR rec_item IN SELECT * FROM jsonb_array_elements(p_input->'items')
    LOOP
        v_producto_busqueda := NULLIF(TRIM(rec_item.value->>'producto'), '');
        v_nuevo_nombre      := NULLIF(TRIM(rec_item.value->>'nuevo_nombre'), '');
        
        -- Casteo seguro de números
        BEGIN
            v_nuevo_precio := (rec_item.value->>'nuevo_precio')::numeric;
            v_nueva_cantidad := (rec_item.value->>'nueva_cantidad')::numeric;
        EXCEPTION WHEN OTHERS THEN
            v_nuevo_precio := NULL;
            v_nueva_cantidad := NULL;
        END;

        IF v_producto_busqueda IS NOT NULL THEN
            
            -- LÓGICA VENTA
            IF v_tipo = 'VENTA' THEN
                -- Buscar ID del detalle (Búsqueda laxa pero priorizando exactitud)
                SELECT id INTO v_item_id 
                FROM public.ventas_detalles 
                WHERE venta_id = v_operacion_id_final 
                  AND (producto ILIKE v_producto_busqueda OR producto ILIKE '%' || v_producto_busqueda || '%')
                ORDER BY length(producto) ASC -- Priorizar el match más corto/exacto
                LIMIT 1;

                IF v_item_id IS NOT NULL THEN
                    UPDATE public.ventas_detalles
                    SET 
                        producto = COALESCE(v_nuevo_nombre, producto),
                        precio_unitario = COALESCE(v_nuevo_precio, precio_unitario),
                        cantidad = COALESCE(v_nueva_cantidad::int, cantidad),
                        subtotal = (COALESCE(v_nueva_cantidad::int, cantidad) * COALESCE(v_nuevo_precio, precio_unitario))
                    WHERE id = v_item_id;
                    v_cambios_realizados := v_cambios_realizados + 1;
                ELSE
                    v_log_errores := v_log_errores || ' No encontré: ' || v_producto_busqueda || '.';
                END IF;

            -- LÓGICA COMPRA
            ELSIF v_tipo = 'COMPRA' THEN
                SELECT id INTO v_item_id 
                FROM public.compras_detalles 
                WHERE compra_id = v_operacion_id_final 
                  AND (producto ILIKE v_producto_busqueda OR producto ILIKE '%' || v_producto_busqueda || '%')
                ORDER BY length(producto) ASC
                LIMIT 1;

                IF v_item_id IS NOT NULL THEN
                    UPDATE public.compras_detalles
                    SET 
                        producto = COALESCE(v_nuevo_nombre, producto),
                        precio_unitario = COALESCE(v_nuevo_precio::text, precio_unitario),
                        cantidad = COALESCE(v_nueva_cantidad, cantidad),
                        -- Cálculo de subtotal en texto para compras
                        subtotal = (COALESCE(v_nueva_cantidad, cantidad) * COALESCE(v_nuevo_precio, precio_unitario::numeric))::text
                    WHERE id = v_item_id;
                    v_cambios_realizados := v_cambios_realizados + 1;
                ELSE
                    v_log_errores := v_log_errores || ' No encontré: ' || v_producto_busqueda || '.';
                END IF;
            END IF;
        END IF;
    END LOOP;

    -- 5. RECALCULO FINAL DE TOTALES
    IF v_cambios_realizados > 0 THEN
        IF v_tipo = 'VENTA' THEN
            SELECT COALESCE(SUM(subtotal), 0) INTO v_total_recalculado 
            FROM public.ventas_detalles WHERE venta_id = v_operacion_id_final;

            UPDATE public.ventas SET total_venta = v_total_recalculado::text WHERE venta_id = v_operacion_id_final;
            
            -- Actualizar movimientos de dinero solo si era Venta (Entrada)
            UPDATE public.movimientos_dinero SET monto = v_total_recalculado::text 
            WHERE referencia_id = v_operacion_id_final AND tipo = 'ENTRADA';

        ELSIF v_tipo = 'COMPRA' THEN
            SELECT COALESCE(SUM(subtotal::numeric), 0) INTO v_total_recalculado 
            FROM public.compras_detalles WHERE compra_id = v_operacion_id_final;

            UPDATE public.compras SET total_compra = v_total_recalculado::text WHERE compra_id = v_operacion_id_final;
            
            -- Actualizar movimientos de dinero solo si era Compra (Salida)
            UPDATE public.movimientos_dinero SET monto = v_total_recalculado::text 
            WHERE referencia_id = v_operacion_id_final AND tipo = 'SALIDA';
        END IF;

        RETURN jsonb_build_object(
            'success', true, 
            'mensaje', '✅ Corrección aplicada (' || v_cambios_realizados || ' ítems). Nuevo Total: $' || v_total_recalculado || '.' || v_log_errores
        );
    ELSE
        RETURN jsonb_build_object(
            'success', false, 
            'error', 'No se pudieron aplicar cambios. ' || v_log_errores
        );
    END IF;

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', 'Error SQL v10: ' || SQLERRM);
END;
$function$

CREATE OR REPLACE FUNCTION public.corregir_operacion_v17(p_input jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_input_norm jsonb;
    v_id_final text;
    v_id_upper text;
    v_tipo text;
    v_items_json jsonb;
    v_pagos_json jsonb;
    rec_item record;
    v_item_id bigint;
    v_old_n text; v_old_q numeric; v_old_p numeric;
    v_new_n text; v_new_q numeric; v_new_p numeric;
    rec_pago record;
    v_mov_id text;
    v_m_ant numeric; v_m_nue numeric;
    v_met_ant text; v_met_nue text;
    v_reporte_detallado text := '';
    v_total_recal numeric := 0;
    v_cambios_realizados int := 0;
    v_salto text := chr(10);
    v_cambios_ia jsonb := '[]'::jsonb;
    v_item_cambio jsonb;
BEGIN
    v_input_norm := CASE WHEN jsonb_typeof(p_input) = 'array' THEN p_input->0 ELSE p_input END;
    v_id_final := NULLIF(TRIM(v_input_norm->>'id_final'), '');
    IF v_id_final IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'ID no especificado.'); END IF;
    IF v_id_final = 'ULTIMA' THEN
        SELECT operacion_id INTO v_id_final FROM public.historial_bot WHERE estado = 'EXITO' AND operacion_id IS NOT NULL ORDER BY log_id DESC LIMIT 1;
        IF v_id_final IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'No hay historial.'); END IF;
    END IF;
    v_id_upper := UPPER(v_id_final);
    v_tipo := split_part(v_id_upper, '_', 1);
    v_reporte_detallado := '🛠️ *Corrección en ' || v_id_upper || '*' || v_salto;
    v_items_json := v_input_norm->'items';
    IF v_items_json IS NOT NULL AND jsonb_array_length(v_items_json) > 0 THEN
        FOR rec_item IN SELECT * FROM jsonb_array_elements(v_items_json) LOOP
            IF v_tipo IN ('RESERVA', 'RES') THEN
                SELECT id, producto, cantidad, precio_unitario INTO v_item_id, v_old_n, v_old_q, v_old_p
                FROM public.reservas_detalles 
                WHERE UPPER(reserva_id) = v_id_upper 
                  AND producto ILIKE '%' || TRIM(rec_item.value->>'producto') || '%' LIMIT 1;
            ELSIF v_tipo = 'COMPRA' THEN
                SELECT id, producto, cantidad, precio_unitario INTO v_item_id, v_old_n, v_old_q, v_old_p
                FROM public.compras_detalles 
                WHERE UPPER(compra_id) = v_id_upper 
                  AND producto ILIKE '%' || TRIM(rec_item.value->>'producto') || '%' LIMIT 1;
            ELSE 
                SELECT id, producto, cantidad::numeric, precio_unitario INTO v_item_id, v_old_n, v_old_q, v_old_p
                FROM public.ventas_detalles 
                WHERE UPPER(venta_id) = v_id_upper 
                  AND producto ILIKE '%' || TRIM(rec_item.value->>'producto') || '%' LIMIT 1;
            END IF;
            IF v_item_id IS NOT NULL THEN
                v_new_n := COALESCE(NULLIF(TRIM(rec_item.value->>'nuevo_nombre'), ''), v_old_n);
                v_new_q := COALESCE((rec_item.value->>'nueva_cantidad')::numeric, v_old_q);
                v_new_p := COALESCE((rec_item.value->>'nuevo_precio')::numeric, v_old_p);
                IF (v_new_n != v_old_n OR v_new_q != v_old_q OR v_new_p != v_old_p) THEN
                    v_item_cambio := jsonb_build_object(
                        'producto_buscado', rec_item.value->>'producto',
                        'antes', jsonb_build_object('nombre', v_old_n, 'cantidad', v_old_q, 'precio', v_old_p),
                        'despues', jsonb_build_object('nombre', v_new_n, 'cantidad', v_new_q, 'precio', v_new_p)
                    );
                    v_cambios_ia := v_cambios_ia || v_item_cambio;
                    v_reporte_detallado := v_reporte_detallado || v_salto || '📦 *' || v_old_n || '*:';
                    IF v_new_n != v_old_n THEN v_reporte_detallado := v_reporte_detallado || v_salto || '  • Nombre: ' || v_old_n || ' ➔ ' || v_new_n; END IF;
                    IF v_new_q != v_old_q THEN v_reporte_detallado := v_reporte_detallado || v_salto || '  • Cant: ' || v_old_q || ' ➔ ' || v_new_q; END IF;
                    IF v_new_p != v_old_p THEN v_reporte_detallado := v_reporte_detallado || v_salto || '  • Precio: $' || v_old_p || ' ➔ $' || v_new_p; END IF;
                    IF v_tipo IN ('RESERVA', 'RES') THEN
                        UPDATE public.reservas_detalles SET producto = v_new_n, cantidad = v_new_q, precio_unitario = v_new_p, subtotal = (v_new_q * v_new_p) WHERE id = v_item_id;
                    ELSIF v_tipo = 'COMPRA' THEN
                        UPDATE public.compras_detalles SET producto = v_new_n, cantidad = v_new_q, precio_unitario = v_new_p, subtotal = (v_new_q * v_new_p) WHERE id = v_item_id;
                    ELSE
                        UPDATE public.ventas_detalles SET producto = v_new_n, cantidad = v_new_q::int, precio_unitario = v_new_p, subtotal = (v_new_q * v_new_p) WHERE id = v_item_id;
                    END IF;
                    UPDATE public.stock_movimientos SET producto = v_new_n WHERE UPPER(referencia_id) = v_id_upper AND producto = v_old_n;
                    v_cambios_realizados := v_cambios_realizados + 1;
                END IF;
            END IF;
        END LOOP;
    END IF;
    v_pagos_json := v_input_norm->'pagos';
    IF v_pagos_json IS NOT NULL AND jsonb_array_length(v_pagos_json) > 0 THEN
        FOR rec_pago IN SELECT * FROM jsonb_array_elements(v_pagos_json) LOOP
            v_m_ant := (rec_pago.value->>'monto_anterior')::numeric;
            v_m_nue := (rec_pago.value->>'nuevo_monto')::numeric;
            v_met_nue := NULLIF(TRIM(rec_pago.value->>'nuevo_metodo'), '');
            SELECT movimiento_id, metodo INTO v_mov_id, v_met_ant FROM public.movimientos_dinero
            WHERE UPPER(referencia_id) = v_id_upper AND monto::numeric = v_m_ant ORDER BY fecha DESC LIMIT 1;
            IF v_mov_id IS NOT NULL AND (v_m_nue != v_m_ant OR (v_met_nue IS NOT NULL AND v_met_nue != v_met_ant)) THEN
                v_reporte_detallado := v_reporte_detallado || v_salto || v_salto || '💵 *Pago Corregido*:';
                IF v_m_nue != v_m_ant THEN v_reporte_detallado := v_reporte_detallado || v_salto || '  • Monto: $' || v_m_ant || ' ➔ $' || v_m_nue; END IF;
                IF v_met_nue IS NOT NULL AND v_met_nue != v_met_ant THEN v_reporte_detallado := v_reporte_detallado || v_salto || '  • Método: ' || v_met_ant || ' ➔ ' || v_met_nue; END IF;
                IF v_m_nue = 0 THEN DELETE FROM public.movimientos_dinero WHERE movimiento_id = v_mov_id;
                ELSE UPDATE public.movimientos_dinero SET monto = v_m_nue, metodo = COALESCE(v_met_nue, metodo) WHERE movimiento_id = v_mov_id;
                END IF;
                v_cambios_realizados := v_cambios_realizados + 1;
            END IF;
        END LOOP;
    END IF;
    IF v_tipo IN ('RESERVA', 'RES') THEN
        PERFORM public.recalcular_reserva(v_id_final); 
        SELECT saldo_pendiente INTO v_total_recal FROM public.reservas WHERE UPPER(reserva_id) = v_id_upper;
        v_reporte_detallado := v_reporte_detallado || v_salto || v_salto || '💰 *Nuevo Saldo Pendiente: $' || v_total_recal || '*';
    ELSIF v_tipo = 'COMPRA' THEN
        SELECT SUM(subtotal::numeric) INTO v_total_recal FROM public.compras_detalles WHERE UPPER(compra_id) = v_id_upper;
        UPDATE public.compras SET total_compra = v_total_recal WHERE UPPER(compra_id) = v_id_upper;
        v_reporte_detallado := v_reporte_detallado || v_salto || v_salto || '💰 *Nuevo Total Compra: $' || v_total_recal || '*';
    ELSE
        SELECT COALESCE(SUM(subtotal), 0) INTO v_total_recal FROM public.ventas_detalles WHERE UPPER(venta_id) = v_id_upper;
        UPDATE public.ventas SET total_venta = v_total_recal WHERE UPPER(venta_id) = v_id_upper;
        v_reporte_detallado := v_reporte_detallado || v_salto || v_salto || '💰 *Nuevo Total Venta: $' || v_total_recal || '*';
    END IF;
    IF v_cambios_realizados = 0 THEN
        v_reporte_detallado := '⚠️ No se detectaron productos o pagos coincidentes para ' || v_id_upper || '.';
    END IF;
    RETURN jsonb_build_object(
        'success', true, 
        'mensaje', v_reporte_detallado,
        'detalles', jsonb_build_object(
            'items', v_cambios_realizados,
            'pagos', v_cambios_realizados,
            'id', v_id_upper
        ),
        'aprendizaje_data', jsonb_build_object(
            'cambios', v_cambios_ia
        )
    );
END;
$function$

CREATE OR REPLACE FUNCTION public.corregir_operacion_v7(p_input jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Variables de entrada
    v_operacion_id_raw text;
    v_operacion_id_final text;
    v_producto_busqueda text;
    v_nuevo_nombre text;
    v_nuevo_precio numeric;
    v_nueva_cantidad int;

    -- Variables internas
    v_tipo text;
    v_item_id bigint;
    v_count int;
    v_nombres_encontrados text;
    v_total_nuevo numeric;
BEGIN
    -- 1. EXTRACCIÓN (Igual que v6)
    v_operacion_id_raw := NULLIF(TRIM(p_input->>'id_final'), '');
    v_producto_busqueda := NULLIF(TRIM(p_input->>'producto'), '');
    v_nuevo_nombre := NULLIF(TRIM(p_input->>'nuevo_nombre'), '');

    BEGIN
        v_nuevo_precio := (p_input->>'nuevo_precio')::numeric;
        v_nueva_cantidad := (p_input->>'nueva_cantidad')::int;
    EXCEPTION WHEN OTHERS THEN
        v_nuevo_precio := NULL; v_nueva_cantidad := NULL;
    END;

    IF v_operacion_id_raw IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'El id_final llegó vacío (NULL).', 'debug_input', p_input);
    END IF;

    -- 2. RESOLVER "ULTIMA"
    IF v_operacion_id_raw = 'ULTIMA' THEN
        SELECT operacion_id INTO v_operacion_id_final
        FROM public.historial_bot WHERE estado = 'EXITO' ORDER BY log_id DESC LIMIT 1;
        IF v_operacion_id_final IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'Historial vacío.'); END IF;
    ELSE
        v_operacion_id_final := v_operacion_id_raw;
    END IF;

    -- 3. DETECTAR TIPO
    v_tipo := split_part(v_operacion_id_final, '_', 1);

    -- 4. LÓGICA VENTA
    IF v_tipo = 'VENTA' THEN
        IF v_producto_busqueda IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'Campo producto vacío.'); END IF;

        -- Buscar coincidencias
        SELECT COUNT(*), STRING_AGG(producto, ', ') INTO v_count, v_nombres_encontrados
        FROM public.ventas_detalles 
        WHERE venta_id = v_operacion_id_final AND producto ILIKE '%' || v_producto_busqueda || '%';

        IF v_count > 1 THEN RETURN jsonb_build_object('success', false, 'error', '⚠️ Ambigüedad: (' || COALESCE(v_nombres_encontrados, '') || '). Sé más específico.'); END IF;
        IF v_count = 0 THEN RETURN jsonb_build_object('success', false, 'error', 'No encontré "' || v_producto_busqueda || '" en ' || v_operacion_id_final); END IF;

        SELECT id INTO v_item_id FROM public.ventas_detalles 
        WHERE venta_id = v_operacion_id_final AND producto ILIKE '%' || v_producto_busqueda || '%' LIMIT 1;

        -- === AQUÍ ESTÁ EL ARREGLO CRÍTICO ===
        -- Usamos ::numeric y ::int en las columnas de la DB para evitar el error de tipos
        UPDATE public.ventas_detalles
        SET 
            producto = COALESCE(v_nuevo_nombre, producto),

            -- Si la columna precio_unitario es texto, esto la convierte temporalmente a número para la lógica
            precio_unitario = COALESCE(v_nuevo_precio, precio_unitario::numeric),

            -- Lo mismo para cantidad
            cantidad = COALESCE(v_nueva_cantidad, cantidad::int),

            -- Calculamos subtotal asegurándonos que todo sea número
            subtotal = (
                COALESCE(v_nueva_cantidad, cantidad::int) * COALESCE(v_nuevo_precio, precio_unitario::numeric)
            )
        WHERE id = v_item_id;

        -- Recalculos (asegurando ::numeric en subtotal por si acaso)
        SELECT COALESCE(SUM(subtotal::numeric),0) INTO v_total_nuevo FROM public.ventas_detalles WHERE venta_id = v_operacion_id_final;
        UPDATE public.ventas SET total = v_total_nuevo WHERE venta_id = v_operacion_id_final;
        UPDATE public.movimientos_dinero SET monto = v_total_nuevo WHERE referencia_id = v_operacion_id_final;

    ELSE
        RETURN jsonb_build_object('success', false, 'error', 'Tipo desconocido: ' || v_operacion_id_final);
    END IF;

    RETURN jsonb_build_object(
        'success', true, 
        'mensaje', '✅ Corrección aplicada a ' || v_operacion_id_final || '. Nuevo Total: $' || v_total_nuevo,
        'datos_usados', jsonb_build_object('id', v_operacion_id_final, 'precio_nuevo', v_nuevo_precio)
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', 'Error SQL v7: ' || SQLERRM);
END;
$function$

