        -- Validaciones
        SELECT COUNT(*), STRING_AGG(producto, ', ') INTO v_count, v_nombres_encontrados
        FROM public.ventas_detalles WHERE venta_id = v_operacion_id_final AND producto ILIKE '%' || v_producto_busqueda || '%';

        IF v_count > 1 THEN RETURN jsonb_build_object('success', false, 'error', '⚠️ Ambigüedad: (' || COALESCE(v_nombres_encontrados, '') || ').'); END IF;
        IF v_count = 0 THEN RETURN jsonb_build_object('success', false, 'error', 'No encontré "' || v_producto_busqueda || '"'); END IF;

